import UIKit
import Foundation

class StockTradeViewController: UIViewController {
    
    var portfolio: [String: Double] = [:] // Stock symbol and quantity
    let apiClient = APIClient()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
    }
    
    func setupUI() {
        // Setup UI elements for trading interface
    }
    
    func executeTrade(symbol: String, quantity: Double, isBuy: Bool) {
        let trade = Trade(symbol: symbol, quantity: quantity, isBuy: isBuy)
        apiClient.executeTrade(trade) { success in
            if success {
                self.updatePortfolio(symbol: symbol, quantity: quantity, isBuy: isBuy)
            } else {
                self.showError("Trade execution failed.")
            }
        }
    }
    
    func updatePortfolio(symbol: String, quantity: Double, isBuy: Bool) {
        if isBuy {
            portfolio[symbol, default: 0] += quantity
        } else {
            portfolio[symbol, default: 0] -= quantity
        }
    }
    
    func showError(_ message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

struct Trade {
    let symbol: String
    let quantity: Double
    let isBuy: Bool
}

class APIClient {
    
    let baseURL = "https://api.yourtradingplatform.com"
    
    func executeTrade(_ trade: Trade, completion: @escaping (Bool) -> Void) {
        guard let url = URL(string: "\(baseURL)/executeTrade") else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let tradeData = ["symbol": trade.symbol, "quantity": trade.quantity, "isBuy": trade.isBuy] as [String : Any]
        
        do {
            request.httpBody = try JSONSerialization.data(withJSONObject: tradeData, options: [])
        } catch {
            completion(false)
            return
        }
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                print("Error: \(error)")
                completion(false)
                return
            }
            completion(true)
        }
        task.resume()
    }
}